algorithm:
Modified greedy insertion with time-window feasibility checking, randomized assign ordering per order, and incremental cost delta tracking to select minimal marginal-cost insertion while guaranteeing each order gets placed via safe fallback to empty assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    type candT struct {
        idx     int
        delta   float64
        ok      bool
    }
    for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
        id := total_ship + shipIdx
        ori, des := oris[shipIdx], dess[shipIdx]
        best := candT{-1, 0, false}
        var order []int
        for i := 0; i < dispatch.AssignsLen; i++ {
            order = append(order, i)
        }
        for i := 0; i < dispatch.AssignsLen/2; i++ {
            j := i + (len(order)-i)/2
            if j < len(order) {
                order[i], order[j] = order[j], order[i]
            }
        }
        for k := range order {
            idx := order[k]
            oldCost := dispatch.Assigns[idx].Cost
            savedState := dispatch.Assigns[idx]
            if dispatch.Assigns[idx].AddShip(id, ori, des) {
                dispatch.Assigns[idx].GenRoute()
                if dispatch.Assigns[idx].Cost >= 0 {
                    delta := dispatch.Assigns[idx].Cost - oldCost
                    if !best.ok || delta < best.delta {
                        best.idx = idx
                        best.delta = delta
                        best.ok = true
                    }
                }
                dispatch.Assigns[idx] = savedState
                dispatch.Assigns[idx].GenRoute()
            }
        }
        targetIdx := best.idx
        if !best.ok {
            if dispatch.AssignsLen < MAXASSIGNS {
                targetIdx = dispatch.AssignsLen
                dispatch.AssignsLen++
            } else {
                targetIdx = 0
            }
        }
        dispatch.Assigns[targetIdx].AddShip(id, ori, des)
        dispatch.Assigns[targetIdx].GenRoute()
    }
    dispatch.RenewnTotalCost()
    return dispatch

